SELECT FLOOR(MIN(min_temp) * 10 / 2) AS adjusted_min_temp
FROM weather_data
WHERE station_id = 1;

SELECT COUNT(run_id) 
  FROM climate_model_runs 
  WHERE STRFTIME('%w', run_date) = '1' AND run_status = 'completed';

SELECT model_name 
FROM climate_models 
WHERE model_accuracy = (SELECT MAX(model_accuracy) FROM climate_models);

SELECT AVG(T1.mean_temp) AS average_temp
FROM weather_data T1
WHERE T1.station_id = 1
AND T1.mean_temp > (
  SELECT AVG(mean_temp) FROM weather_data
);

SELECT admin_name, contact_number
FROM station_administrators
WHERE admin_id = 0;
